SELECT game_id, date, home_team, away_team, attendance
FROM games
WHERE score_home > score_away;

SELECT DISTINCT u.user_id, u.username, u.email, al.access_time, al.game_id
FROM users u
JOIN access_logs al ON u.user_id = al.user_id;

SELECT AVG(play_count) as average_plays
FROM (
    SELECT game_id, COUNT(*) as play_count
    FROM plays
    GROUP BY game_id
);

SELECT game_id
FROM game_trends
WHERE trend_type = 'offensive' AND trend_score > 80;
